function autoFormatTime(e){let t=e.value.replace(/\D/g,"");switch(t.length>4&&(t=t.slice(0,4)),t.length){case 0:case 1:case 2:e.value=t;break;case 3:if(parseInt(t.slice(0,2),10)<=23)e.value=t.slice(0,2)+":"+t.slice(2);else{let l=t.slice(0,1).padStart(2,"0"),a=t.slice(1);e.value=l+":"+a}break;case 4:let l=t.slice(0,2),a=t.slice(2);e.value=l+":"+a}}function transformTimeValue(e){let t=e.trim();if(/^\d{2}$/.test(t))return`${t[0].padStart(2,"0")}:${t[1].padStart(2,"0")}`;if(/^\d{3,4}$/.test(t))return 3===t.length?parseInt(t.slice(0,2),10)<=23?t.slice(0,2)+":"+t.slice(2):t.slice(0,1).padStart(2,"0")+":"+t.slice(1):t.slice(0,2)+":"+t.slice(2);if(t.includes(":")){let[e,l]=t.split(":");return l||(l="00"),e=e.padStart(2,"0"),l=l.padStart(2,"0"),`${e}:${l}`}return t}